        if (typeof user === "string") {
          try {
            const parsed = JSON.parse(user);
            this.userInfo.username = parsed.username || "";
          } catch (error) {
            this.userInfo.username = "";
          }
          return;
        }
        this.userInfo.username = user.username || "";
